var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_A","text":{"KOREA":"정지! 정지!","JPN":"止まれ！　止まれ！","ENG":"Stop, stop!","TWN":"停車！停車！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_A","text":{"KOREA":"현재 도시관리국의 긴급지침에 따라\xA0차량 검문을 진행 중이니 잠시 협조를……","JPN":"ただいま都市管理局の緊急指針により車両検問を行っていますので、少しご協力を……","ENG":"Due to the current emergency guidelines of the City Management, you must attend the vehicle inspectio–","TWN":"現在根據城市管理局的緊急措施實施臨檢，請你配合……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_A","text":{"KOREA":"음?","JPN":"うむ？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_A","text":{"KOREA":"거기. 신원확인을 위해 잠깐 가면을 벗어주시죠.","JPN":"そちらの方。身元確認のために仮面を脱いでもらえませんか。","ENG":"You there. Please remove your mask for your ID verification.","TWN":"麻煩一下，脫下面具讓我們可以確認你的身分。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"여기 녀석들에게 알려라. 하바키가 왔다고.","JPN":"ここのやつらに知らせろ。覇吐が来たと。","ENG":"Tell these fools that Habaki has arrived.","TWN":"你去告訴他們，就說幅木來了。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEADER_NPC_NANAHARA2_NULL","text":{"KOREA":"뻔뻔하구나, 하바키 전 당주. 이곳에 낯짝을 드러내다니.","JPN":"図々しいな、覇吐元当主。ここに顔を出すとは。","ENG":"Habaki... The nerve of you to show up like this.","TWN":"幅木前堂主，你還真是厚顏無恥，竟然有臉出現在這裡。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"어서 길이나 열어라. 네놈들과 잡담이나 나눌 시간은 없다.","JPN":"早く道を開けろ。貴様らと雑談をしている暇はない。","ENG":"Open up already. I do not have any time to spare for you lot.","TWN":"快讓路，我沒時間和閒雜人等攪和。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_A","text":{"KOREA":"뭐야? 정말로 관리국이 이송하던 죄수가 여기에 나타난 건가?","JPN":"なんだ？　本当に管理局が移送していた囚人がここに現れたのか？","ENG":"What? So the prisoner really showed up?","TWN":"什麼？管理局移送的犯人出現在這裡？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_VOICE_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_A","text":{"KOREA":"차량을 타고 멀쩡히 도시 경계를 벗어나려 하다니. 제정신이 아니군.","JPN":"車両に乗って堂々と都市の境界を抜け出そうとするなんて。正気じゃないな。","ENG":"He tried to escape using a car, through the city borders. Crazy, if you ask me.","TWN":"你還想搭車離開城市邊境，你腦子沒問題吧？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_VOICE_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"흥, 그렇게 못할 것도 없지.","JPN":"ふん、できないこともないがな。","ENG":"Hmph, I don’t see why not.","TWN":"哼，這有什麼難的。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_VOICE_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_A","text":{"KOREA":"당장 차에서 내려! 불응하면 발포하겠다!","JPN":"今すぐ車から降りろ！　応じないと発砲する！","ENG":"Get out of your car! We will fire upon any resistance!","TWN":"立刻給我下車！要是敢反抗我們就立刻開槍！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_VOICE_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_A","text":{"KOREA":"엇? 방금 무슨 소리였지?","JPN":"あ？　今のは何の音だ？","ENG":"Huh? What was that sound?","TWN":"嗯？剛剛那是什麼聲音？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_B","text":{"KOREA":"전자기 펄스다! 주변 방어포탑들 전부 먹통이 됐어!","JPN":"電磁パルスだ！　周りの防御砲塔が全部動かなくなったぞ！","ENG":"An EMP! The surrounding turrets are all jammed!","TWN":"是電磁脈衝！周圍的防禦砲塔沒辦法運作！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_A","text":{"KOREA":"이 자식이! 방금 막 탈출한 죄수 주제에 무슨 수로……!","JPN":"この野郎！　今脱出したばっかりの囚人のくせにどうやって……！","ENG":"You bastard! How did you even–!","TWN":"你這傢伙！逃犯還敢給我搞鬼……！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEADER_NPC_NANAHARA2_NULL","text":{"KOREA":"건물 옥상으로부터 기습이다! 엄폐해!","JPN":"建物の屋上から奇襲だ！　隠れろ！","ENG":"An ambush from the building roof! Take cover!","TWN":"攻擊是從屋頂來的！找掩護！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"WOMAN_EXTRA_NULL_NULL","text":{"KOREA":"구, 구해 주셔서 감사합니다. 덕분에 살았어요.","JPN":"た、助けていただきありがとうございます。おかげで命びろいしました。","ENG":"Th-thank you for saving us. If it wasn’t for you, we would’ve been dead.","TWN":"謝…謝，謝謝你的救命之恩。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"아이들을 데리고 어서 안전한 곳으로 대피하십시오.","JPN":"子どもたちを連れて早く安全なところに避難してください。","ENG":"Take the children and evacuate to a safe area, now.","TWN":"快帶著孩子躲到安全的地方。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"WOMAN_EXTRA_NULL_NULL","text":{"KOREA":"네…… 네!","JPN":"は……はい！","ENG":"Oh... Yes, ma’am!","TWN":"喔……好！"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"이 소리는…… 남동방 연합이 지키는 곳?","JPN":"この音は……連合の南東軍が守っている地域か？","ENG":"This sound... It’s coming from where the Southeastern Alliance is.","TWN":"這個聲音是……東南方聯盟看守的地方？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"무전은 없지만 총성이 교차하고 있다.","JPN":"無線はないが銃声が行き交っている。","ENG":"No message by radio, but I hear gunshots.","TWN":"雖然沒有無線電，但有此起彼落的槍聲。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"침식체와 교전하고 있는 게 아니군.","JPN":"侵食体と交戦しているわけではないようだな。","ENG":"It’s not a C.O. they’re fighting off.","TWN":"不是在和侵蝕體交手。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"서둘러야 해.","JPN":"急がなければ。","ENG":"I must hurry.","TWN":"必須動作快！"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};